class Solution:
    def numberOfGoodSubarraySplits(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        ones_idx = [i for i, v in enumerate(nums) if v == 1]
        if not ones_idx:
            return 0
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            total = 0
            for j in range(i):
                sub = nums[j:i]
                if sub.count(1) == 1:
                    total = (total + dp[j]) % MOD
            dp[i] = total
        return dp[n]

