var numberOfGoodSubarraySplits = function(nums) {
    const MOD = 1000000007;
    const ones = [];
    for (let i = 0; i < nums.length; i++) if (nums[i] === 1) ones.push(i);
    if (ones.length === 0) return 0;
    let ans = 1;
    for (let i = 1; i < ones.length; i++) {
        const gap = ones[i] - ones[i - 1];
        ans = (ans * gap) % MOD;
    }
    return ans;
};
